package workloadmanager

import (
	"context"
	"testing"
	"time"

	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/client-go/kubernetes/fake"

	"github.com/anomalyco/agentcube/pkg/common/types"
)

func TestNewK8sClient(t *testing.T) {
	scheme := runtime.NewScheme()
	_ = corev1.AddToScheme(scheme)
}

func TestK8sClient_CreateAgentRuntime(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"
	sandbox := &types.SandboxInfo{
		SessionID:      "test-session-123",
		Name:           "test-agent",
		Namespace:      namespace,
		Kind:           types.KindAgentRuntime,
		Labels:         map[string]string{"app": "test"},
		Annotations:    map[string]string{"description": "test sandbox"},
		CreatedAt:      time.Now(),
		ExpiresAt:      time.Now().Add(24 * time.Hour),
		LastActivityAt: time.Now(),
	}

	t.Run("creates pod with correct metadata", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		client := &K8sClient{
			clientset: clientset,
			scheme:    runtime.NewScheme(),
		}

		podName, err := client.CreateAgentRuntime(ctx, sandbox, nil, "")
		if err != nil {
			t.Fatalf("CreateAgentRuntime() error = %v", err)
		}

		if podName == "" {
			t.Error("Pod name should not be empty")
		}

		pod, err := clientset.CoreV1().Pods(namespace).Get(ctx, podName, metav1.GetOptions{})
		if err != nil {
			t.Fatalf("Failed to get created pod: %v", err)
		}

		if pod.Labels["app.kubernetes.io/name"] != sandbox.Name {
			t.Errorf("Pod name label = %v, want %v", pod.Labels["app.kubernetes.io/name"], sandbox.Name)
		}
		if pod.Labels["agentcube.io/session-id"] != sandbox.SessionID {
			t.Errorf("Session ID label = %v, want %v", pod.Labels["agentcube.io/session-id"], sandbox.SessionID)
		}
		if pod.Labels["agentcube.io/kind"] != types.KindAgentRuntime {
			t.Errorf("Kind label = %v, want %v", pod.Labels["agentcube.io/kind"], types.KindAgentRuntime)
		}
	})

	t.Run("creates pod with runtime class", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		client := &K8sClient{
			clientset: clientset,
			scheme:    runtime.NewScheme(),
		}

		runtimeClassName := "kata-containers"
		podName, err := client.CreateAgentRuntime(ctx, sandbox, nil, runtimeClassName)
		if err != nil {
			t.Fatalf("CreateAgentRuntime() error = %v", err)
		}

		pod, _ := clientset.CoreV1().Pods(namespace).Get(ctx, podName, metav1.GetOptions{})
		if pod.Spec.RuntimeClassName == nil || *pod.Spec.RuntimeClassName != runtimeClassName {
			t.Errorf("RuntimeClassName = %v, want %v", pod.Spec.RuntimeClassName, runtimeClassName)
		}
	})

	t.Run("creates pod with template", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		client := &K8sClient{
			clientset: clientset,
			scheme:    runtime.NewScheme(),
		}

		template := &types.SandboxTemplate{
			Spec: metav1.PodTemplateSpec{
				Spec: corev1.PodSpec{
					Containers: []corev1.Container{
						{
							Name:  "main",
							Image: "nginx:latest",
							Ports: []corev1.ContainerPort{{ContainerPort: 80}},
						},
					},
				},
			},
		}

		podName, err := client.CreateAgentRuntime(ctx, sandbox, template, "")
		if err != nil {
			t.Fatalf("CreateAgentRuntime() error = %v", err)
		}

		pod, _ := clientset.CoreV1().Pods(namespace).Get(ctx, podName, metav1.GetOptions{})
		if len(pod.Spec.Containers) != 1 {
			t.Errorf("Container count = %v, want 1", len(pod.Spec.Containers))
		}
		if pod.Spec.Containers[0].Image != "nginx:latest" {
			t.Errorf("Container image = %v, want nginx:latest", pod.Spec.Containers[0].Image)
		}
	})
}

func TestK8sClient_DeleteAgentRuntime(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("deletes existing pod", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-pod",
				Namespace: namespace,
			},
		}
		_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod, metav1.CreateOptions{})

		client := &K8sClient{clientset: clientset}
		err := client.DeleteAgentRuntime(ctx, namespace, "test-pod")
		if err != nil {
			t.Errorf("DeleteAgentRuntime() error = %v", err)
		}
	})

	t.Run("handles already deleted pod", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		client := &K8sClient{clientset: clientset}

		err := client.DeleteAgentRuntime(ctx, namespace, "nonexistent-pod")
		if err != nil {
			t.Errorf("DeleteAgentRuntime() should not error for nonexistent pod: %v", err)
		}
	})
}

func TestK8sClient_CreateCodeInterpreter(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"
	sandbox := &types.SandboxInfo{
		SessionID:      "test-session-456",
		Name:           "test-interpreter",
		Namespace:      namespace,
		Kind:           types.KindCodeInterpreter,
		Labels:         map[string]string{"app": "interpreter"},
		CreatedAt:      time.Now(),
		ExpiresAt:      time.Now().Add(24 * time.Hour),
		LastActivityAt: time.Now(),
	}

	t.Run("creates code interpreter pod", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		client := &K8sClient{
			clientset: clientset,
			scheme:    runtime.NewScheme(),
		}

		podName, err := client.CreateCodeInterpreter(ctx, sandbox, nil, "")
		if err != nil {
			t.Fatalf("CreateCodeInterpreter() error = %v", err)
		}

		pod, _ := clientset.CoreV1().Pods(namespace).Get(ctx, podName, metav1.GetOptions{})
		if pod.Labels["app.kubernetes.io/component"] != "code-interpreter" {
			t.Errorf("Component label = %v, want code-interpreter", pod.Labels["app.kubernetes.io/component"])
		}
	})
}

func TestK8sClient_GetPod(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("gets existing pod", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-pod",
				Namespace: namespace,
			},
		}
		_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod, metav1.CreateOptions{})

		client := &K8sClient{clientset: clientset}
		got, err := client.GetPod(ctx, namespace, "test-pod")
		if err != nil {
			t.Errorf("GetPod() error = %v", err)
		}
		if got.Name != "test-pod" {
			t.Errorf("Pod name = %v, want test-pod", got.Name)
		}
	})

	t.Run("error for nonexistent pod", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		client := &K8sClient{clientset: clientset}

		_, err := client.GetPod(ctx, namespace, "nonexistent")
		if err == nil {
			t.Error("GetPod() should return error for nonexistent pod")
		}
	})
}

func TestK8sClient_GetPodIP(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("gets pod IP", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-pod",
				Namespace: namespace,
			},
			Status: corev1.PodStatus{
				PodIP: "10.0.0.1",
			},
		}
		_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod, metav1.CreateOptions{})

		client := &K8sClient{clientset: clientset}
		ip, err := client.GetPodIP(ctx, namespace, "test-pod")
		if err != nil {
			t.Errorf("GetPodIP() error = %v", err)
		}
		if ip != "10.0.0.1" {
			t.Errorf("Pod IP = %v, want 10.0.0.1", ip)
		}
	})

	t.Run("error when pod has no IP", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-pod-noip",
				Namespace: namespace,
			},
			Status: corev1.PodStatus{},
		}
		_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod, metav1.CreateOptions{})

		client := &K8sClient{clientset: clientset}
		_, err := client.GetPodIP(ctx, namespace, "test-pod-noip")
		if err == nil {
			t.Error("GetPodIP() should return error when pod has no IP")
		}
	})
}

func TestK8sClient_WaitForPodReady(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("waits for ready pod", func(t *testing.T) {
		clientset := fake.NewSimpleClientset()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "ready-pod",
				Namespace: namespace,
			},
			Status: corev1.PodStatus{
				Phase: corev1.PodRunning,
				Conditions: []corev1.PodCondition{
					{
						Type:   corev1.PodReady,
						Status: corev1.ConditionTrue,
					},
				},
			},
		}
		_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod, metav1.CreateOptions{})

		client := &K8sClient{clientset: clientset}
		err := client.WaitForPodReady(ctx, namespace, "ready-pod", 5*time.Second)
		if err != nil {
			t.Errorf("WaitForPodReady() error = %v", err)
		}
	})
}

func TestK8sClient_ListPodsByLabel(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	clientset := fake.NewSimpleClientset()
	pod1 := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "pod-1",
			Namespace: namespace,
			Labels:    map[string]string{"app": "test"},
		},
	}
	pod2 := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "pod-2",
			Namespace: namespace,
			Labels:    map[string]string{"app": "test"},
		},
	}
	pod3 := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "pod-3",
			Namespace: namespace,
			Labels:    map[string]string{"app": "other"},
		},
	}
	_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod1, metav1.CreateOptions{})
	_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod2, metav1.CreateOptions{})
	_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod3, metav1.CreateOptions{})

	client := &K8sClient{clientset: clientset}
	pods, err := client.ListPodsByLabel(ctx, namespace, "app=test")
	if err != nil {
		t.Errorf("ListPodsByLabel() error = %v", err)
	}
	if len(pods.Items) != 2 {
		t.Errorf("Pod count = %v, want 2", len(pods.Items))
	}
}

func TestK8sClient_DeletePodsByLabel(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	clientset := fake.NewSimpleClientset()
	pod1 := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "pod-1",
			Namespace: namespace,
			Labels:    map[string]string{"app": "delete-me"},
		},
	}
	pod2 := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "pod-2",
			Namespace: namespace,
			Labels:    map[string]string{"app": "keep-me"},
		},
	}
	_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod1, metav1.CreateOptions{})
	_, _ = clientset.CoreV1().Pods(namespace).Create(ctx, pod2, metav1.CreateOptions{})

	client := &K8sClient{clientset: clientset}
	err := client.DeletePodsByLabel(ctx, namespace, "app=delete-me")
	if err != nil {
		t.Errorf("DeletePodsByLabel() error = %v", err)
	}
}

func TestK8sClient_BuildLabels(t *testing.T) {
	client := &K8sClient{}
	sandbox := &types.SandboxInfo{
		Labels: map[string]string{"custom": "label"},
	}

	labels := client.buildLabels(sandbox)

	if labels["custom"] != "label" {
		t.Errorf("Custom label = %v, want label", labels["custom"])
	}
}

func TestK8sClient_BuildAnnotations(t *testing.T) {
	client := &K8sClient{}
	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID:      "test-session",
		CreatedAt:      now,
		ExpiresAt:      now.Add(24 * time.Hour),
