	"k8s.io/client-go/kubernetes/fake"

	"github.com/anomalyco/agentcube/pkg/common/types"
)

type testK8sClient struct {
	clientset *fake.Clientset
	scheme    *runtime.Scheme
}

func newTestK8sClient() *testK8sClient {
	return &testK8sClient{
		clientset: fake.NewSimpleClientset(),
		scheme:    runtime.NewScheme(),
	}
}

func (c *testK8sClient) createPod(ctx context.Context, namespace string, pod *corev1.Pod) (*corev1.Pod, error) {
	return c.clientset.CoreV1().Pods(namespace).Create(ctx, pod, metav1.CreateOptions{})
}

func (c *testK8sClient) getPod(ctx context.Context, namespace, name string) (*corev1.Pod, error) {
	return c.clientset.CoreV1().Pods(namespace).Get(ctx, name, metav1.GetOptions{})
}

func (c *testK8sClient) deletePod(ctx context.Context, namespace, name string) error {
	return c.clientset.CoreV1().Pods(namespace).Delete(ctx, name, metav1.DeleteOptions{})
}

func (c *testK8sClient) listPods(ctx context.Context, namespace, labelSelector string) (*corev1.PodList, error) {
	return c.clientset.CoreV1().Pods(namespace).List(ctx, metav1.ListOptions{
		LabelSelector: labelSelector,
	})
}

func TestK8sClient_CreatePod(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("creates pod with correct metadata", func(t *testing.T) {
		client := newTestK8sClient()
		sandbox := &types.SandboxInfo{
			SessionID:      "test-session-123",
			Name:           "test-agent",
			Namespace:      namespace,
			Kind:           types.KindAgentRuntime,
			Labels:         map[string]string{"app": "test"},
			Annotations:    map[string]string{"description": "test sandbox"},
			CreatedAt:      time.Now(),
			ExpiresAt:      time.Now().Add(24 * time.Hour),
			LastActivityAt: time.Now(),
		}

		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:        sandbox.Name + "-" + sandbox.SessionID[:8],
				Namespace:   namespace,
				Labels:      sandbox.Labels,
				Annotations: sandbox.Annotations,
			},
			Spec: corev1.PodSpec{
				Containers: []corev1.Container{
					{Name: "main", Image: "busybox"},
				},
			},
		}

		created, err := client.createPod(ctx, namespace, pod)
		if err != nil {
			t.Fatalf("createPod() error = %v", err)
		}

		if created.Name != pod.Name {
			t.Errorf("Pod name = %v, want %v", created.Name, pod.Name)
		}
		if created.Labels["app"] != "test" {
			t.Errorf("Pod label = %v, want test", created.Labels["app"])
		}
	})

	t.Run("creates pod with runtime class", func(t *testing.T) {
		client := newTestK8sClient()
		runtimeClassName := "kata-containers"

		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-pod-runtime",
				Namespace: namespace,
			},
			Spec: corev1.PodSpec{
				RuntimeClassName: &runtimeClassName,
				Containers: []corev1.Container{
					{Name: "main", Image: "nginx"},
				},
			},
		}

		created, err := client.createPod(ctx, namespace, pod)
		if err != nil {
			t.Fatalf("createPod() error = %v", err)
		}

		if created.Spec.RuntimeClassName == nil || *created.Spec.RuntimeClassName != runtimeClassName {
			t.Errorf("RuntimeClassName = %v, want %v", created.Spec.RuntimeClassName, runtimeClassName)
		}
	})
}

func TestK8sClient_GetPod(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("gets existing pod", func(t *testing.T) {
		client := newTestK8sClient()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-pod-get",
				Namespace: namespace,
			},
		}
		_, _ = client.createPod(ctx, namespace, pod)

		got, err := client.getPod(ctx, namespace, "test-pod-get")
		if err != nil {
			t.Errorf("getPod() error = %v", err)
		}
		if got.Name != "test-pod-get" {
			t.Errorf("Pod name = %v, want test-pod-get", got.Name)
		}
	})

	t.Run("error for nonexistent pod", func(t *testing.T) {
		client := newTestK8sClient()

		_, err := client.getPod(ctx, namespace, "nonexistent")
		if err == nil {
			t.Error("getPod() should return error for nonexistent pod")
		}
	})
}

func TestK8sClient_DeletePod(t *testing.T) {
	ctx := context.Background()
