		err := client.deletePod(ctx, namespace, "test-pod-delete")
		if err != nil {
			t.Errorf("deletePod() error = %v", err)
		}

		_, err = client.getPod(ctx, namespace, "test-pod-delete")
		if err == nil {
			t.Error("Pod should be deleted")
		}
	})
}

