			Labels:    map[string]string{"app": "other"},
		},
	}
	_, _ = client.createPod(ctx, namespace, pod1)
	_, _ = client.createPod(ctx, namespace, pod2)
	_, _ = client.createPod(ctx, namespace, pod3)

