func TestK8sClient_PodReady(t *testing.T) {
	ctx := context.Background()
	namespace := "test-namespace"

	t.Run("pod ready condition", func(t *testing.T) {
		client := newTestK8sClient()
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "ready-pod",
				Namespace: namespace,
			},
			Status: corev1.PodStatus{
				Phase: corev1.PodRunning,
				Conditions: []corev1.PodCondition{
					{
						Type:   corev1.PodReady,
						Status: corev1.ConditionTrue,
					},
				},
			},
		}
		_, _ = client.createPod(ctx, namespace, pod)

		got, err := client.getPod(ctx, namespace, "ready-pod")
		if err != nil {
			t.Errorf("getPod() error = %v", err)
		}

		if got.Status.Phase != corev1.PodRunning {
			t.Errorf("Pod phase = %v, want Running", got.Status.Phase)
		}

		foundReady := false
		for _, cond := range got.Status.Conditions {
			if cond.Type == corev1.PodReady && cond.Status == corev1.ConditionTrue {
				foundReady = true
			}
		}
		if !foundReady {
			t.Error("Pod should have Ready condition")
		}
	})
}

