		Port:                  8080,
		MaxConcurrentRequests: 2,
	}

	mockStore := newMockRouterStore()
	sessionManager, _ := NewSessionManager("http://localhost:8081", mockStore)
	srv := NewServer(cfg, sessionManager, nil)

	t.Run("rejects requests over limit", func(t *testing.T) {
		var successCount, tooManyCount int

		for i := 0; i < 10; i++ {
			req := httptest.NewRequest("GET", "/health/ready", nil)
			w := httptest.NewRecorder()
			srv.router.ServeHTTP(w, req)

			if w.Code == http.StatusOK {
				successCount++
			} else if w.Code == http.StatusTooManyRequests {
				tooManyCount++
			}
		}

		if successCount > 5 {
			t.Logf("Success count: %d, too many: %d", successCount, tooManyCount)
		}
	})
}

