	if claims == nil {
		claims = jwt.MapClaims{
			"sub": "test-session",
			"exp": time.Now().Add(1 * time.Hour).Unix(),
			"iat": time.Now().Unix(),
		}
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	tokenString, err := token.SignedString(privateKey)
	if err != nil {
		t.Fatalf("Failed to sign token: %v", err)
	}
	return tokenString
}

func TestRouterJWTAuth(t *testing.T) {
	gin.SetMode(gin.TestMode)
	privateKey, publicKey := generateTestRSAKeyPair(t)

	t.Run("Test-RT-1: Invalid JWT returns 401", func(t *testing.T) {
		router := gin.New()
		router.Use(gin.Recovery())

		router.Use(func(c *gin.Context) {
			authHeader := c.GetHeader("Authorization")
			if authHeader == "" {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
				c.Abort()
				return
			}

			parts := strings.Split(authHeader, " ")
			if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header format"})
				c.Abort()
				return
			}

			tokenString := parts[1]
			token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
				if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
					return nil, jwt.ErrSignatureInvalid
				}
				return publicKey, nil
			})

			if err != nil || !token.Valid {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
				c.Abort()
				return
			}

			c.Next()
		})

		router.GET("/protected", func(c *gin.Context) {
			c.JSON(http.StatusOK, gin.H{"message": "success"})
		})

		tests := []struct {
			name       string
			token      string
			wantStatus int
		}{
			{
				name:       "missing auth header",
				token:      "",
				wantStatus: http.StatusUnauthorized,
			},
			{
				name:       "invalid token format",
				token:      "Bearer invalid-token",
				wantStatus: http.StatusUnauthorized,
			},
			{
				name:       "malformed Bearer prefix",
				token:      "bearer valid-token",
				wantStatus: http.StatusUnauthorized,
			},
			{
				name:       "no Bearer prefix",
				token:      "some-token",
				wantStatus: http.StatusUnauthorized,
			},
		}

		for _, tt := range tests {
			t.Run(tt.name, func(t *testing.T) {
				req := httptest.NewRequest("GET", "/protected", nil)
				if tt.token != "" {
					req.Header.Set("Authorization", tt.token)
				}
				w := httptest.NewRecorder()

				router.ServeHTTP(w, req)

				if w.Code != tt.wantStatus {
					t.Errorf("Status = %d, want %d", w.Code, tt.wantStatus)
				}
			})
		}
	})

	t.Run("Test-RT-2: Expired JWT returns Token Expired error", func(t *testing.T) {
		router := gin.New()
		router.Use(gin.Recovery())

		router.Use(func(c *gin.Context) {
			authHeader := c.GetHeader("Authorization")
			if authHeader == "" {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
				c.Abort()
				return
			}

			parts := strings.Split(authHeader, " ")
			if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header format"})
				c.Abort()
				return
			}

			tokenString := parts[1]
			token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
				if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
					return nil, jwt.ErrSignatureInvalid
				}
				return publicKey, nil
			})

			if err != nil || !token.Valid {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid token", "detail": err.Error()})
				c.Abort()
				return
			}

			c.Next()
		})

		router.GET("/protected", func(c *gin.Context) {
			c.JSON(http.StatusOK, gin.H{"message": "success"})
		})

		expiredClaims := jwt.MapClaims{
			"sub": "test-session",
			"exp": time.Now().Add(-1 * time.Hour).Unix(),
			"iat": time.Now().Add(-2 * time.Hour).Unix(),
		}
		token := generateTestJWTToken(t, privateKey, expiredClaims)

		req := httptest.NewRequest("GET", "/protected", nil)
		req.Header.Set("Authorization", "Bearer "+token)
		w := httptest.NewRecorder()

		router.ServeHTTP(w, req)

		if w.Code != http.StatusUnauthorized {
			t.Errorf("Status = %d, want %d", w.Code, http.StatusUnauthorized)
		}

		var response map[string]interface{}
		if err := json.Unmarshal(w.Body.Bytes(), &response); err == nil {
			if errMsg, ok := response["error"].(string); ok {
				if !strings.Contains(strings.ToLower(errMsg), "token") {
					t.Errorf("Error message should indicate token issue, got: %s", errMsg)
				}
			}
		}
	})

	t.Run("valid JWT passes authentication", func(t *testing.T) {
		router := gin.New()
		router.Use(gin.Recovery())

		router.Use(func(c *gin.Context) {
			authHeader := c.GetHeader("Authorization")
			if authHeader == "" {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
				c.Abort()
				return
			}

			parts := strings.Split(authHeader, " ")
			if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header format"})
				c.Abort()
				return
			}

			tokenString := parts[1]
			token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
				if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
					return nil, jwt.ErrSignatureInvalid
				}
				return publicKey, nil
			})

			if err != nil || !token.Valid {
				c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
				c.Abort()
				return
			}

			c.Next()
		})

		router.GET("/protected", func(c *gin.Context) {
			c.JSON(http.StatusOK, gin.H{"message": "success"})
		})

		token := generateTestJWTToken(t, privateKey, nil)

		req := httptest.NewRequest("GET", "/protected", nil)
		req.Header.Set("Authorization", "Bearer "+token)
		w := httptest.NewRecorder()

		router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Status = %d, want %d", w.Code, http.StatusOK)
		}
	})
}

func TestRouterProxy(t *testing.T) {
	gin.SetMode(gin.TestMode)

	t.Run("Test-RT-3: Backend timeout returns Gateway Timeout", func(t *testing.T) {
		backend := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			time.Sleep(2 * time.Second)
			w.WriteHeader(http.StatusOK)
		}))
		defer backend.Close()

		backendURL := strings.TrimPrefix(backend.URL, "http://")
		parts := strings.Split(backendURL, ":")
		podIP := parts[0] + ":" + parts[1]

		proxy := NewProxy()
		proxy.SetTimeout(100 * time.Millisecond)

		w := httptest.NewRecorder()
		c, _ := gin.CreateTestContext(w)
		c.Request = httptest.NewRequest("GET", "/test", nil)

		proxy.ProxyRequest(c, podIP, "/test")

		if w.Code != http.StatusGatewayTimeout {
			t.Errorf("Status = %d, want %d", w.Code, http.StatusGatewayTimeout)
		}
	})

	t.Run("Test-RT-4: Headers are passed through correctly", func(t *testing.T) {
		var receivedHeaders http.Header

		backend := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			receivedHeaders = r.Header.Clone()
			w.Header().Set("X-Backend-Header", "backend-value")
			w.WriteHeader(http.StatusOK)
			w.Write([]byte("response"))
		}))
		defer backend.Close()

		backendURL := strings.TrimPrefix(backend.URL, "http://")
		parts := strings.Split(backendURL, ":")
		podIP := parts[0] + ":" + parts[1]

		proxy := NewProxy()

		w := httptest.NewRecorder()
		c, _ := gin.CreateTestContext(w)
		c.Request = httptest.NewRequest("GET", "/test", nil)
		c.Request.Header.Set("X-Custom-Header", "custom-value")
		c.Request.Header.Set("X-Forwarded-For", "192.168.1.1")
		c.Request.Header.Set("Authorization", "Bearer token123")

		proxy.ProxyRequest(c, podIP, "/test")

		if w.Code != http.StatusOK {
			t.Errorf("Status = %d, want %d", w.Code, http.StatusOK)
		}

		if receivedHeaders.Get("X-Custom-Header") != "custom-value" {
			t.Errorf("X-Custom-Header = %v, want custom-value", receivedHeaders.Get("X-Custom-Header"))
		}

		if w.Header().Get("X-Backend-Header") != "backend-value" {
			t.Errorf("X-Backend-Header = %v, want backend-value", w.Header().Get("X-Backend-Header"))
		}
	})
}

