func TestRouterProxyErrorMapping(t *testing.T) {
	gin.SetMode(gin.TestMode)

	proxy := NewProxy()

	t.Run("connection refused maps to 502", func(t *testing.T) {
		w := httptest.NewRecorder()
		c, _ := gin.CreateTestContext(w)
		c.Request = httptest.NewRequest("GET", "/test", nil)

		proxy.ProxyRequest(c, "127.0.0.1:9999", "/test")

		if w.Code != http.StatusBadGateway {
			t.Errorf("Status = %d, want %d", w.Code, http.StatusBadGateway)
		}
	})

	t.Run("maps status codes correctly", func(t *testing.T) {
		tests := []struct {
			name         string
			backendCode  int
			expectedCode int
		}{
			{"200 OK", http.StatusOK, http.StatusOK},
			{"404 Not Found", http.StatusNotFound, http.StatusNotFound},
