func TestPicoDResourceLimits(t *testing.T) {
	workspace := t.TempDir()
	srv := newTestServer(t, workspace, nil)

	t.Run("Test-PD-1: Command timeout kills process", func(t *testing.T) {
		body := `{"command": "sleep", "args": ["10"], "timeout": "1s"}`
		req := httptest.NewRequest("POST", "/api/execute", strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()

		srv.router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Execute handler returned %d, want %d", w.Code, http.StatusOK)
		}

		var response ExecuteResponse
		if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
			t.Fatalf("Failed to unmarshal response: %v", err)
		}

		if !response.TimedOut {
			t.Error("TimedOut should be true for timeout command")
		}
		if response.ExitCode != TimeoutExitCode {
			t.Errorf("ExitCode = %d, want %d (TimeoutExitCode)", response.ExitCode, TimeoutExitCode)
		}
	})

	t.Run("Command with short timeout succeeds", func(t *testing.T) {
		body := `{"command": "echo", "args": ["hello"], "timeout": "5s"}`
		req := httptest.NewRequest("POST", "/api/execute", strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()

		srv.router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Execute handler returned %d, want %d", w.Code, http.StatusOK)
		}

		var response ExecuteResponse
		if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
			t.Fatalf("Failed to unmarshal response: %v", err)
		}

		if response.TimedOut {
			t.Error("TimedOut should be false for fast command")
		}
		if response.ExitCode != 0 {
			t.Errorf("ExitCode = %d, want 0", response.ExitCode)
		}
	})

	t.Run("Default timeout applied when not specified", func(t *testing.T) {
		body := `{"command": "echo", "args": ["test"]}`
		req := httptest.NewRequest("POST", "/api/execute", strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()

		srv.router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Execute handler returned %d, want %d", w.Code, http.StatusOK)
		}
	})
}

func TestPicoDLargeOutput(t *testing.T) {
	workspace := t.TempDir()
	srv := newTestServer(t, workspace, nil)

	t.Run("Test-PD-2: Large output handling (>1MB)", func(t *testing.T) {
		body := `{"command": "python3", "args": ["-c", "print('x' * 2000000)"]}`
		req := httptest.NewRequest("POST", "/api/execute", strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()

		srv.router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Execute handler returned %d, want %d", w.Code, http.StatusOK)
		}

		var response ExecuteResponse
		if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
			t.Fatalf("Failed to unmarshal response: %v", err)
		}

		if len(response.Stdout) < 2000000 {
			t.Errorf("Stdout length = %d, expected >= 2000000", len(response.Stdout))
		}
		if response.ExitCode != 0 {
			t.Errorf("ExitCode = %d, want 0", response.ExitCode)
		}
	})

	t.Run("Large stderr handling", func(t *testing.T) {
		body := `{"command": "python3", "args": ["-c", "import sys; sys.stderr.write('e' * 1500000)"]}`
		req := httptest.NewRequest("POST", "/api/execute", strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()

		srv.router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Execute handler returned %d, want %d", w.Code, http.StatusOK)
		}

		var response ExecuteResponse
		if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
			t.Fatalf("Failed to unmarshal response: %v", err)
		}

		if len(response.Stderr) < 1500000 {
			t.Errorf("Stderr length = %d, expected >= 1500000", len(response.Stderr))
		}
	})

	t.Run("Combined large stdout and stderr", func(t *testing.T) {
		body := `{"command": "python3", "args": ["-c", "import sys; print('o' * 500000); sys.stderr.write('e' * 500000)"]}`
		req := httptest.NewRequest("POST", "/api/execute", strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()

		srv.router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("Execute handler returned %d, want %d", w.Code, http.StatusOK)
		}

		var response ExecuteResponse
		if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
			t.Fatalf("Failed to unmarshal response: %v", err)
		}

		if len(response.Stdout) < 500000 {
			t.Errorf("Stdout length = %d, expected >= 500000", len(response.Stdout))
		}
