metadata.output:
.PHONY: all build test clean docker-build docker-push lint fmt vet coverage generate gen-crd gen-client gen-all gen-check gen-copyright e2e e2e-clean help

GO ?= go
GOFMT ?= gofmt
GOBIN ?= $(shell $(GO) env GOPATH)/bin
DOCKER ?= docker
KIND ?= kind

VERSION ?= $(shell git describe --tags --always --dirty 2>/dev/null || echo "v0.0.0")
IMAGE_REGISTRY ?= ghcr.io/anomalyco
IMAGE_TAG ?= $(VERSION)

all: build test

build:
	@echo "Building binaries..."
	$(GO) build -o bin/workload-manager ./cmd/workload-manager
	$(GO) build -o bin/router ./cmd/router
	$(GO) build -o bin/agentd ./cmd/agentd
	$(GO) build -o bin/picod ./cmd/picod

test:
	@echo "Running tests..."
	$(GO) test -v -race -coverprofile=coverage.out ./...

coverage: test
	@echo "Generating coverage report..."
	$(GO) tool cover -html=coverage.out -o coverage.html
	@echo "Coverage report: coverage.html"

lint:
	@echo "Running linters..."
	@which golangci-lint > /dev/null || curl -sSfL https://raw.githubusercontent.com/golangci/golangci-lint/master/install.sh | sh -s -- -b $(GOBIN) v1.57.0
	golangci-lint run ./...

fmt:
	@echo "Formatting code..."
	$(GOFMT) -s -w .

vet:
	@echo "Running go vet..."
	$(GO) vet ./...

clean:
	@echo "Cleaning..."
	rm -rf bin/
	rm -f coverage.out coverage.html

docker-build:
	@echo "Building Docker images..."
	$(DOCKER) build -f docker/Dockerfile -t $(IMAGE_REGISTRY)/agentcube:$(IMAGE_TAG) .
	$(DOCKER) build -f docker/Dockerfile.router -t $(IMAGE_REGISTRY)/agentcube-router:$(IMAGE_TAG) .
	$(DOCKER) build -f docker/Dockerfile.picod -t $(IMAGE_REGISTRY)/agentcube-picod:$(IMAGE_TAG) .

docker-push:
	@echo "Pushing Docker images..."
	$(DOCKER) push $(IMAGE_REGISTRY)/agentcube:$(IMAGE_TAG)
	$(DOCKER) push $(IMAGE_REGISTRY)/agentcube-router:$(IMAGE_TAG)
	$(DOCKER) push $(IMAGE_REGISTRY)/agentcube-picod:$(IMAGE_TAG)

generate: gen-all

gen-crd:
	@echo "Generating CRDs..."
	@which controller-gen > /dev/null || $(GO) install sigs.k8s.io/controller-tools/cmd/controller-gen@latest
	controller-gen crd:crdVersions=v1 paths="./pkg/apis/..." output:crd:dir=manifests/charts/base/crds

gen-client:
	@echo "Generating client code..."
	@which client-gen > /dev/null || $(GO) install k8s.io/code-generator/cmd/client-gen@latest
	client-gen --clientset-name versioned \
		--input-base "github.com/anomalyco/agentcube/pkg/apis" \
		--input "runtime/v1alpha1" \
		--output-package "github.com/anomalyco/agentcube/pkg/generated/clientset" \
		--go-header-file hack/boilerplate.go.txt

gen-all: gen-crd gen-client
	@echo "Generating deepcopy..."
	@which controller-gen > /dev/null || $(GO) install sigs.k8s.io/controller-tools/cmd/controller-gen@latest
	controller-gen object:headerFile=hack/boilerplate.go.txt paths="./pkg/apis/..."

gen-check:
	@echo "Checking generated code..."
	$(MAKE) gen-all
	@if [ -n "$$(git status --porcelain)" ]; then \
		echo "Generated code is out of date. Please run 'make gen-all'"; \
		exit 1; \
	fi

gen-copyright:
	@echo "Adding copyright headers..."
	@for f in $$(find . -name "*.go" -not -path "./vendor/*"); do \
		if ! grep -q "Copyright" $$f; then \
			cat hack/boilerplate.go.txt $$f > $$f.tmp && mv $$f.tmp $$f; \
		fi; \
	done

e2e:
	@echo "Running E2E tests..."
	$(GO) test -v -tags=e2e ./test/e2e/...

e2e-clean:
	@echo "Cleaning E2E environment..."
	$(KIND) delete cluster --name agentcube-e2e || true

helm-lint:
	@echo "Linting Helm chart..."
	helm lint manifests/charts/base

helm-template:
	@echo "Templating Helm chart..."
	helm template agentcube manifests/charts/base

help:
	@echo "Available targets:"
	@echo "  build         - Build all binaries"
	@echo "  test          - Run unit tests"
	@echo "  coverage      - Generate test coverage report"
	@echo "  lint          - Run linters"
